sql:
SELECT MAX(last_used) AS last_ability_used
FROM character_abilities
WHERE character_id = 0;

SELECT name
FROM abilities
WHERE power > 50;

SELECT name
FROM abilities
WHERE power = (SELECT MAX(power) FROM abilities);

SELECT SUM(usage_count) AS total_usage
FROM character_abilities
WHERE ability_id = 1;

external_knowledge:
; The top three most damaging abilities refer to the abilities with the highest average damage dealt; 
; Characters and abilities are entities in a fictional game or simulation; 
; Average damage dealt is a measure of the damage an ability causes to opponents.

sql:
